#!/bin/bash
WT=/localdev/wransom/tt-metal/.claude/worktrees/agent-a48fa14207415d0cb
cd "$WT"
# resnet50 REAL config: bf8 weights, bf16 out, LoFi, fp32_accum=False, packer_l1_acc ON, TILE output, bias
RN="CB_WEIGHTS_DTYPE=bfloat8_b CB_OUT_DTYPE=bfloat16 CB_IN_DTYPE=bfloat16 CB_FP32_ACCUM=false CB_FIDELITY=LoFi CB_L1_ACC=true CB_OUT_LAYOUT=tile CB_BIAS=true"
run () { echo ">>> $1"; env MODEL=resnet50 LABEL="$1" $RN $2 bash "$WT/conv_bench_tools/cb_bench.sh" 2 main helper_sbm helper_trm; }
run "rn50_L1_64<-64_56x56_s1_HS"      "CB_BATCH=20 CB_OUT_CH=64  CB_IN_CH=64   CB_H=56 CB_W=56 CB_FILTER=3 CB_STRIDE=1 CB_PAD=1,1,1,1 CB_SHARD=HS"
run "rn50_L2a_128<-128_56x56_s2_HS"   "CB_BATCH=20 CB_OUT_CH=128 CB_IN_CH=128  CB_H=56 CB_W=56 CB_FILTER=3 CB_STRIDE=2 CB_PAD=1,1,1,1 CB_SHARD=HS"
run "rn50_L2b_128<-128_28x28_s1_HS"   "CB_BATCH=20 CB_OUT_CH=128 CB_IN_CH=128  CB_H=28 CB_W=28 CB_FILTER=3 CB_STRIDE=1 CB_PAD=1,1,1,1 CB_SHARD=HS"
run "rn50_L3a_256<-256_28x28_s2_BS"   "CB_BATCH=20 CB_OUT_CH=256 CB_IN_CH=256  CB_H=28 CB_W=28 CB_FILTER=3 CB_STRIDE=2 CB_PAD=1,1,1,1 CB_SHARD=BS"
run "rn50_L3b_256<-256_14x14_s1_BS"   "CB_BATCH=20 CB_OUT_CH=256 CB_IN_CH=256  CB_H=14 CB_W=14 CB_FILTER=3 CB_STRIDE=1 CB_PAD=1,1,1,1 CB_SHARD=BS"
run "rn50_L4a_512<-512_14x14_s2_BS"   "CB_BATCH=20 CB_OUT_CH=512 CB_IN_CH=512  CB_H=14 CB_W=14 CB_FILTER=3 CB_STRIDE=2 CB_PAD=1,1,1,1 CB_SHARD=BS"
run "rn50_L4b_512<-512_7x7_s1_BS"     "CB_BATCH=20 CB_OUT_CH=512 CB_IN_CH=512  CB_H=7  CB_W=7  CB_FILTER=3 CB_STRIDE=1 CB_PAD=1,1,1,1 CB_SHARD=BS"
run "rn50_DS1_256<-64_56x56_1x1s2_HS" "CB_BATCH=20 CB_OUT_CH=256 CB_IN_CH=64   CB_H=56 CB_W=56 CB_FILTER=1 CB_STRIDE=2 CB_PAD=0,0,0,0 CB_SHARD=HS"
run "rn50_DS2_1024<-512_28x28_1x1s2_BS" "CB_BATCH=20 CB_OUT_CH=1024 CB_IN_CH=512 CB_H=28 CB_W=28 CB_FILTER=1 CB_STRIDE=2 CB_PAD=0,0,0,0 CB_SHARD=BS"
run "rn50_DS3_2048<-1024_14x14_1x1s2_BS" "CB_BATCH=20 CB_OUT_CH=2048 CB_IN_CH=1024 CB_H=14 CB_W=14 CB_FILTER=1 CB_STRIDE=2 CB_PAD=0,0,0,0 CB_SHARD=BS"
run "rn50_stem_64<-16_115x115_4x4s1_HS" "CB_BATCH=16 CB_OUT_CH=64 CB_IN_CH=16 CB_H=115 CB_W=115 CB_FILTER=4 CB_STRIDE=1 CB_PAD=0,0,0,0 CB_SHARD=HS CB_ABH=256"
echo "=== RN50 COLLECTION COMPLETE ==="
